import React, { Component } from "react";

class App extends Component {

  constructor(props){
    super(props);
    this.state = {
      nome : "Mateus",
      contador: 0
    }
    this.aumentar = this.aumentar.bind(this);
    this.diminuir = this.diminuir.bind(this);
  }

  aumentar(){
    let state = this.state;
    state.contador+=1;
    state.nome="José";
    this.setState(state);
  }

  diminuir(){
    let state = this.state;
    if(state.contador >= 0){
      state.contador-=1;
      state.nome="Chico";
    }
    this.setState(state);
  }

  render() {
    return (
      <div>
          <h1>Contador {this.state.nome}</h1>
          <h3>            
            Contador {this.state.contador}
          </h3>
          <button onClick={this.aumentar}>+</button>
          <button onClick={this.diminuir}>-</button>
      </div>
    );
  }
}

export default App;
